async function getGeneralSettings(){const e=window.BRAND||{},t=e.contact||{};if("function"==typeof window.loadGeneralInfo)try{const n=await window.loadGeneralInfo();if(n)return{brandName:n.brand_name||e.name||"Store",brandNameAr:n.brand_name_ar||e.nameAr||e.name||"Store",contactPhone:n.phone_number||t.phone||"+962777777777",contactEmail:n.email_address||t.email||"info@example.com",copyrightYear:(new Date).getFullYear().toString(),location:"Amman, Jordan",locationAr:"عمان، الأردن",minimumOrderAmount:n.minimum_order_amount||25}}catch(e){console.warn("API unavailable, using defaults:",e)}const n=localStorage.getItem("generalSettings");return n?JSON.parse(n):{brandName:e.name||"Store",brandNameAr:e.nameAr||e.name||"Store",contactPhone:t.phone||"+962777777777",contactEmail:t.email||"info@example.com",copyrightYear:(new Date).getFullYear().toString(),location:"Amman, Jordan",locationAr:"عمان، الأردن",minimumOrderAmount:25}}function saveGeneralSettings(e){return localStorage.setItem("generalSettings",JSON.stringify(e)),!0}async function applyGeneralSettings(){try{const e=await getGeneralSettings(),t="undefined"!=typeof currentLanguage?currentLanguage:"en";document.querySelectorAll(".topbaic-logo, .brand-name, [data-brand]").forEach(n=>{n.hasAttribute("data-en")?(n.setAttribute("data-en",e.brandName),n.setAttribute("data-ar",e.brandNameAr||e.brandName),n.textContent="ar"===t&&e.brandNameAr||e.brandName):n.textContent=e.brandName}),document.querySelectorAll(".footer-bottom p, .copyright").forEach(t=>{(t.textContent.includes("©")||t.textContent.includes("2026"))&&(t.textContent=`© ${e.copyrightYear} ${e.brandName}. All rights reserved.`)}),document.querySelectorAll(".location").forEach(n=>{n.hasAttribute("data-en")?(n.setAttribute("data-en",e.location),n.setAttribute("data-ar",e.locationAr),n.textContent="ar"===t?e.locationAr:e.location):n.textContent=e.location}),console.log("✅ General settings applied")}catch(e){console.error("Error applying general settings:",e)}}"loading"===document.readyState?document.addEventListener("DOMContentLoaded",applyGeneralSettings):applyGeneralSettings(),"undefined"!=typeof window&&(window.getGeneralSettings=getGeneralSettings,window.saveGeneralSettings=saveGeneralSettings,window.applyGeneralSettings=applyGeneralSettings),console.log("✅ settings.js loaded - Using database via general-info.js");